Greedy insertion minimizing marginal cost per unit load distance while considering time window feasibility, with fallback to least‑crowded existing assign or a fresh assign.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const bigFloat = 1e100
	for idx := range oris {
		shipID := total_ship + idx
		ori := oris[idx]
		des := dess[idx]
		type cand struct {
			idx       int
			score     float64
			isNewSlot bool
		}
		var candidates []cand
		var saved [MAXASSIGNS]struct {
			station Station
			cost    float64
		}
		baseLoadDist := float64(ori.Load) * cal_dis(ori, des)
		for i := 0; i < dispatch.AssignsLen; i++ {
			saved[i].station = dispatch.Assigns[i].StationCurrent
			saved[i].cost = dispatch.Assigns[i].Cost
			if dispatch.Assigns[i].AddShip(shipID, ori, des) {
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				if newCost >= 0 && newCost >= saved[i].cost {
					marginal := newCost - saved[i].cost
					loadFactor := 1.0
					if baseLoadDist > 0 {
						loadFactor = marginal / baseLoadDist
					}
					timePen := 0.0
					if ori.TimeEnd > 0 && ori.TimeEnd < 86400 && des.TimeEnd > 0 && des.TimeEnd < 86400 {
						windowTightness := float64((des.TimeEnd - des.TimeStart) + (ori.TimeEnd - ori.TimeStart))
						if windowTightness <= 120 {
							timePen = 0.15 * marginal
						}
					}
					score := marginal + timePen*loadFactor
					candidates = append(candidates, cand{idx: i, score: score, isNewSlot: false})
				}
				dispatch.Assigns[i].RemoveShip(shipID)
				dispatch.Assigns[i].StationCurrent = saved[i].station
				dispatch.Assigns[i].Cost = saved[i].cost
			}
		}
		if dispatch.AssignsLen < MAXASSIGNS {
			j := dispatch.AssignsLen
			saved[j].station = dispatch.Assigns[j].StationCurrent
			saved[j].cost = dispatch.Assigns[j].Cost
			if dispatch.Assigns[j].AddShip(shipID, ori, des) {
				dispatch.Assigns[j].GenRoute()
				newCost := dispatch.Assigns[j].Cost
				if newCost >= 0 {
					marginal := newCost - saved[j].cost
					loadFactor := 1.0
					if baseLoadDist > 0 {
						loadFactor = marginal / baseLoadDist
					}
					score := marginal + 0.3*marginal*loadFactor
					candidates = append(candidates, cand{idx: j, score: score, isNewSlot: true})
				}
				dispatch.Assigns[j].RemoveShip(shipID)
				dispatch.Assigns[j].StationCurrent = saved[j].station
				dispatch.Assigns[j].Cost = saved[j].cost
			}
		}
		bestIdx := -1
		bestScore := bigFloat
		for _, c := range candidates {
			if c.score < bestScore {
				bestScore = c.score
				bestIdx = c.idx
			}
		}
		if bestIdx >= 0 {
			dispatch.Assigns[bestIdx].AddShip(shipID, ori, des)
			dispatch.Assigns[bestIdx].GenRoute()
			if bestIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen++
			}
		} else {
			fallbackIdx := -1
			fallbackBusy := bigFloat
			for i := 0; i < dispatch.AssignsLen; i++ {
				busy := dispatch.Assigns[i].Cost
				if busy < fallbackBusy {
					fallbackBusy = busy
					fallbackIdx = i
				}
			}
			if fallbackIdx >= 0 && dispatch.Assigns[fallbackIdx].AddShip(shipID, ori, des) {
				dispatch.Assigns[fallbackIdx].GenRoute()
			} else if dispatch.AssignsLen < MAXASSIGNS {
				k := dispatch.AssignsLen
				dispatch.Assigns[k].AddShip(shipID, ori, des)
				dispatch.Assigns[k].GenRoute()
				dispatch.AssignsLen++
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

